from models import Product

class Inventory:
    def __init__(self):
        self.products = {}

    def add_product(self, name, price, stock):
        self.products[name] = Product(name, price, stock)

    def check_stock(self, name, quantity):
        if name not in self.products:
            return False
        return self.products[name].stock > quantity

    def reserve_stock(self, name, quantity):
        if not self.check_stock(name, quantity):
            raise ValueError(f'Insufficient stock for {name}')
        self.products[name].stock -= quantity

    def get_product(self, name):
        return self.products.get(name)

