from models import Order, OrderItem
from inventory import Inventory

class OrderProcessor:
    def __init__(self, inventory):
        self.inventory = inventory
        self.orders = []

    def create_order(self, customer_name, items, discount_percent=0):
        order = Order(customer_name)
        for item_name, qty in items:
            product = self.inventory.get_product(item_name)
            if product is None:
                raise ValueError(f'Product {item_name} not found')
            self.inventory.reserve_stock(item_name, qty)
            order.add_item(OrderItem(product, qty))
        order.discount = discount_percent
        self.orders.append(order)
        return order

    def get_order_summary(self, order):
        return {
            'customer': order.customer_name,
            'items': len(order.items),
            'total': order.total()
        }
